descriptor.controllerScript:
var ctx;
self.onInit = function() {
  ctx = self.ctx;
  ctx.$scope.displayVal = '--';
  ctx.$scope.unitText = ctx.widgetConfig.units || '';
  ctx.$scope.labelText = ctx.widgetConfig.title || 'Value';
  ctx.$scope.iconText = (ctx.settings && ctx.settings.icon) || '📊';
  ctx.$scope.barColor = '#334155';
  ctx.$scope.valueColor = '#ffffff';
};
self.onDataUpdated = function() {
  try {
    if (!ctx.data || !ctx.data.length) return;
    var d = ctx.data[0];
    if (!d || !d.data || !d.data.length) return;
    var raw = d.data[d.data.length - 1][1];
    var num = parseFloat(raw);
    if (!isNaN(num)) {
      var dec = (ctx.widgetConfig.decimals !== undefined && ctx.widgetConfig.decimals !== null) ? ctx.widgetConfig.decimals : 1;
      ctx.$scope.displayVal = num.toFixed(dec);
      var maxV = (ctx.settings && ctx.settings.maxVal) ? parseFloat(ctx.settings.maxVal) : 100;
      var pct = Math.min(100, (num / maxV) * 100);
      if (pct >= 75) { ctx.$scope.barColor = '#00e676'; ctx.$scope.valueColor = '#00e676'; }
      else if (pct >= 40) { ctx.$scope.barColor = '#ffb300'; ctx.$scope.valueColor = '#ffb300'; }
      else { ctx.$scope.barColor = '#ff5252'; ctx.$scope.valueColor = '#ff5252'; }
    } else {
      ctx.$scope.displayVal = raw || '--';
      ctx.$scope.barColor = '#3b82f6';
      ctx.$scope.valueColor = '#3b82f6';
    }
    ctx.detectChanges();
  } catch(e) {}
};
self.onDestroy = function() {};

var ctx;
var stateColors = {
  'RUNNING': '#00e676', 'running': '#00e676', '1': '#00e676',
  'STOPPED': '#ff5252', 'stopped': '#ff5252', '0': '#ff5252',
  'IDLE': '#ffb300', 'idle': '#ffb300',
  'ALARM': '#ff1744', 'alarm': '#ff1744',
  'FAULT': '#ff1744', 'fault': '#ff1744',
  'AUTO': '#00e676', 'auto': '#00e676'
};
self.onInit = function() {
  ctx = self.ctx;
  ctx.$scope.stateText = '---';
  ctx.$scope.ringColor = '#334155';
};
self.onDataUpdated = function() {
  try {
    if (!ctx.data || !ctx.data.length || !ctx.data[0].data || !ctx.data[0].data.length) return;
    var raw = String(ctx.data[0].data[ctx.data[0].data.length - 1][1]);
    ctx.$scope.stateText = raw.toUpperCase().substring(0, 10);
    ctx.$scope.ringColor = stateColors[raw] || stateColors[raw.toUpperCase()] || '#3b82f6';
    ctx.detectChanges();
  } catch(e) {}
};
self.onDestroy = function() {};

var ctx;
self.onInit = function() {
  ctx = self.ctx;
  ctx.$scope.pctText = '--';
  ctx.$scope.arcColor = '#334155';
  ctx.$scope.arcLen = 0;
  ctx.$scope.labelText = ctx.widgetConfig.title || 'OEE';
  ctx.$scope.zoneText = 'NO DATA';
};
self.onDataUpdated = function() {
  try {
    if (!ctx.data || !ctx.data.length || !ctx.data[0].data || !ctx.data[0].data.length) return;
    var raw = parseFloat(ctx.data[0].data[ctx.data[0].data.length - 1][1]);
    if (isNaN(raw)) return;
    var pct = Math.max(0, Math.min(100, raw));
    ctx.$scope.pctText = pct.toFixed(1) + '%';
    ctx.$scope.arcLen = (pct / 100) * 314;
    if (pct >= 75) { ctx.$scope.arcColor = '#00e676'; ctx.$scope.zoneText = 'WORLD CLASS'; }
    else if (pct >= 50) { ctx.$scope.arcColor = '#ffb300'; ctx.$scope.zoneText = 'IMPROVING'; }
    else { ctx.$scope.arcColor = '#ff5252'; ctx.$scope.zoneText = 'ACTION NEEDED'; }
    ctx.detectChanges();
  } catch(e) {}
};
self.onDestroy = function() {};

var ctx;
self.onInit = function() {
  ctx = self.ctx;
  ctx.$scope.partsVal = '--';
  ctx.$scope.targetVal = '--';
  ctx.$scope.fillPct = 0;
  ctx.$scope.barColor = '#334155';
  ctx.$scope.attainText = '0%';
  ctx.$scope.titleText = ctx.widgetConfig.title || 'Production';
};
self.onDataUpdated = function() {
  try {
    var parts = 0, target = 0;
    if (ctx.data && ctx.data.length >= 1 && ctx.data[0].data && ctx.data[0].data.length) {
      parts = parseFloat(ctx.data[0].data[ctx.data[0].data.length - 1][1]) || 0;
    }
    if (ctx.data && ctx.data.length >= 2 && ctx.data[1].data && ctx.data[1].data.length) {
      target = parseFloat(ctx.data[1].data[ctx.data[1].data.length - 1][1]) || 0;
    }
    ctx.$scope.partsVal = Math.round(parts);
    ctx.$scope.targetVal = target > 0 ? Math.round(target) : '?';
    var pct = target > 0 ? Math.min(100, (parts / target) * 100) : 0;
    ctx.$scope.fillPct = pct;
    ctx.$scope.attainText = pct.toFixed(1) + '%';
    if (pct >= 90) ctx.$scope.barColor = '#00e676';
    else if (pct >= 70) ctx.$scope.barColor = '#ffb300';
    else ctx.$scope.barColor = '#ff5252';
    ctx.detectChanges();
  } catch(e) {}
};
self.onDestroy = function() {};

var ctx;
var keyLabels = {
  'is_running':'Running','auto_mode':'Auto Mode','alarm_active':'Alarm',
  'motion_status':'In Motion','run_status':'Run Status','connection_status':'Connected',
  'emergency':'Emergency'
};
self.onInit = function() {
  ctx = self.ctx;
  ctx.$scope.titleText = ctx.widgetConfig.title || 'Status';
  ctx.$scope.items = [];
};
self.onDataUpdated = function() {
  try {
    var items = [];
    for (var i = 0; i < ctx.data.length; i++) {
      var d = ctx.data[i];
      if (!d || !d.data || !d.data.length) continue;
      var raw = d.data[d.data.length - 1][1];
      var keyName = d.dataKey ? d.dataKey.name : ('key' + i);
      var label = keyLabels[keyName] || keyName.replace(/_/g,' ');
      var num = parseFloat(raw);
      var isOn = (!isNaN(num) && num > 0) || raw === true || raw === 'true' || raw === '1' || raw === 'RUNNING' || raw === 'ON';
      var color = isOn ? '#00e676' : '#ff5252';
      if (keyName === 'alarm_active' && isOn) color = '#ff1744';
      if (keyName === 'emergency' && isOn) color = '#ff1744';
      items.push({ label: label, val: isOn ? 'ON' : 'OFF', color: color });
    }
    ctx.$scope.items = items;
    ctx.detectChanges();
  } catch(e) {}
};
self.onDestroy = function() {};
